import React from 'react';
import { Card, Stack, Divider, Text, Heading, Box } from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

export default function GeneratedComponent(props: Props) {
  const { city, temperature, condition, humidity, windSpeed, unit = 'C', forecast } = props;

  return (
    <Card shadow="md" padding={24} radius="lg" border={true}>
      <Stack gap={24}>
        {/* Header Section */}
        <Stack gap={4}>
          <Heading level={3}>{city}</Heading>
          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">{condition}</Text>
        </Stack>

        {/* Hero Section */}
        <Stack direction="horizontal" align="center" justify="between">
          <Heading level={1} color="var(--ggui-color-primary-600)">
            {temperature}°{unit}
          </Heading>
          <Box padding={16} borderRadius="md" background="var(--ggui-color-surfaceVariant)">
             <Text size="3xl" aria-label={`Condition: ${condition}`}>
               {condition === 'Sunny' ? '☀️' : condition === 'Rainy' ? '🌧️' : '⛅'}
             </Text>
          </Box>
        </Stack>

        {/* Metrics Section */}
        <Stack direction="horizontal" justify="between">
          <Stack gap={4}>
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Humidity</Text>
            <Text variant="body">{humidity}%</Text>
          </Stack>
          <Stack gap={4}>
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Wind Speed</Text>
            <Text variant="body">{windSpeed} km/h</Text>
          </Stack>
        </Stack>

        <Divider margin={0} color="var(--ggui-color-outlineVariant)" />

        {/* Forecast Section */}
        <Stack direction="horizontal" justify="between" gap={8}>
          {forecast.map((item, index) => (
            <Stack key={index} align="center" gap={4}>
              <Text variant="caption" weight="semibold">{item.day ?? 'N/A'}</Text>
              <Text variant="bodyLarge">{item.icon ?? '☁️'}</Text>
              <Stack direction="horizontal" gap={4}>
                <Text variant="label">{item.high ?? 0}°</Text>
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">{item.low ?? 0}°</Text>
              </Stack>
            </Stack>
          ))}
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useState, useMemo, useEffect } from 'react';
import { Container, Stack, Card, Box, Text, Heading, Input } from '@ggui-ai/design/primitives';

interface Props {
  elements: Array<{
    atomicNumber?: number;
    symbol?: string;
    name?: string;
    atomicWeight?: number;
    category?: string;
    row?: number;
    col?: number;
  }>;
}

const CATEGORY_COLORS: Record<string, string> = {
  'noble-gas': 'var(--ggui-color-primary-200)',
  'halogen': 'var(--ggui-color-warning-200)',
  'alkali-metal': 'var(--ggui-color-success-200)',
  'nonmetal': 'var(--ggui-color-info-200)',
  'transition-metal': 'var(--ggui-color-neutral-200)',
};

export default function GeneratedComponent(props: Props) {
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedElement, setSelectedElement] = useState<Props['elements'][0] | null>(null);

  useEffect(() => {
    const handleAgentData = (event: Event) => {
      console.log('Agent data received:', (event as CustomEvent).detail);
    };
    window.addEventListener('ggui:agent-data', handleAgentData as EventListener);
    return () => window.removeEventListener('ggui:agent-data', handleAgentData as EventListener);
  }, []);

  const filteredElements = useMemo(() => {
    const q = searchQuery.toLowerCase();
    return props.elements.filter(
      (el) =>
        el.name?.toLowerCase().includes(q) ||
        el.symbol?.toLowerCase().includes(q)
    );
  }, [props.elements, searchQuery]);

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-4)">
      <Stack gap="var(--ggui-spacing-6)">
        <Input
          label="Search Elements"
          placeholder="Search by name or symbol..."
          value={searchQuery}
          onChange={setSearchQuery}
        />

        <div
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(18, 1fr)',
            gap: 'var(--ggui-spacing-1)',
          }}
        >
          {props.elements.map((el, i) => {
            const isMatch = filteredElements.includes(el);
            return (
              <Box
                key={i}
                padding="var(--ggui-spacing-1)"
                style={{
                  gridRow: el.row,
                  gridColumn: el.col,
                  backgroundColor: CATEGORY_COLORS[el.category ?? ''] ?? 'var(--ggui-color-neutral-200)',
                  opacity: isMatch ? 1 : 0.2,
                  cursor: 'pointer',
                  borderRadius: 'var(--ggui-shape-radius-sm)',
                  textAlign: 'center',
                  minHeight: 'var(--ggui-spacing-12)',
                  transition: 'opacity 200ms ease',
                }}
                onClick={() => setSelectedElement(el)}
              >
                <Text size="xs" style={{ textAlign: 'left' }}>{el.atomicNumber}</Text>
                <Heading level={5}>{el.symbol}</Heading>
              </Box>
            );
          })}
        </div>

        {selectedElement && (
          <Card padding="var(--ggui-spacing-4)">
            <Stack gap="var(--ggui-spacing-2)">
              <Heading level={3}>{selectedElement.name} ({selectedElement.symbol})</Heading>
              <Text>Atomic Number: {selectedElement.atomicNumber ?? 'N/A'}</Text>
              <Text>Atomic Weight: {selectedElement.atomicWeight ?? 'N/A'}</Text>
              <Text>Category: {selectedElement.category ?? 'N/A'}</Text>
            </Stack>
          </Card>
        )}

        <Stack
          direction="horizontal"
          gap="var(--ggui-spacing-4)"
          justify="center"
          style={{ padding: 'var(--ggui-spacing-4)' }}
        >
          {Object.keys(CATEGORY_COLORS).map((cat) => (
            <Stack key={cat} direction="horizontal" align="center" gap="var(--ggui-spacing-1)">
              <Box style={{ width: 16, height: 16, backgroundColor: CATEGORY_COLORS[cat] }} />
              <Text variant="caption">{cat.replace('-', ' ')}</Text>
            </Stack>
          ))}
        </Stack>
      </Stack>
    </Container>
  );
}

import React from 'react';
import { Container, Card, Stack, Text, Heading, Divider } from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  // Example: "Tokyo"
  /** Current temperature */
  temperature: number;
  // Example: 28
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  // Example: "Sunny"
  /** Humidity percentage */
  humidity: number;
  // Example: 45
  /** Wind speed */
  windSpeed: number;
  // Example: 8
  /** Temperature unit (C or F) */
  unit?: string;
  // Example: "C"
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
  // Example: [
  //   {
  //     "day": "Mon",
  //     "icon": "☀️",
  //     "high": 30,
  //     "low": 22
  //   },
  //   ...
  // ]
}

export default function GeneratedComponent(props: Props) {
  const unitEffective = props.unit ?? 'C';

  const onSurface = 'var(--ggui-color-onSurface, var(--ggui-color-neutral-900, #111827))';
  const onSurfaceVariant = 'var(--ggui-color-onSurfaceVariant, #52525b)';
  const surfaceVariant = 'var(--ggui-color-surfaceVariant, #f4f4f5)';
  const outline = 'var(--ggui-color-outline, var(--ggui-color-outlineVariant, #d4d4d8))';

  const formatTemperature = (value: number) => `${value} ${unitEffective}`;

  const forecastSlots = React.useMemo(() => {
    const src = props.forecast ?? [];
    const slice = src.slice(0, 5);
    if (slice.length >= 5) return slice;

    const missing = 5 - slice.length;
    return [
      ...slice,
      ...Array.from({ length: missing }, () => ({
        day: undefined,
        icon: undefined,
        high: undefined,
        low: undefined,
      })),
    ];
  }, [props.forecast]);

  const metricBoxStyle: React.CSSProperties = {
    flex: '1 1 220px',
    padding: 'var(--ggui-spacing-2, 8px)',
    background: surfaceVariant,
    borderRadius: 'var(--ggui-shape-radius-md, 8px)',
    border: `1px solid ${outline}`,
  };

  return (
    <Container maxWidth="lg" padding={0}>
      <Card shadow="md" padding={24} radius="lg">
        <Stack gap={16}>
          <div
            style={{
              display: 'flex',
              gap: 'var(--ggui-spacing-4, 16px)',
              flexWrap: 'wrap',
              alignItems: 'flex-start',
            }}
          >
            <Stack gap={8} style={{ flex: '1 1 280px', minWidth: 240 }}>
              <Text variant="label" color={onSurfaceVariant}>
                {props.city}
              </Text>

              <Stack gap={6}>
                <Heading level={2} color={onSurface}>
                  {formatTemperature(props.temperature)}
                </Heading>

                <Stack direction="horizontal" gap={8} align="center" wrap={false} justify="start">
                  <Text variant="bodyLarge" color={onSurface}>
                    <span aria-hidden="true" style={{ marginRight: 'var(--ggui-spacing-1, 4px)' }}>
                      {(() => {
                        const c = props.condition?.toLowerCase?.() ?? '';
                        if (c.includes('sun') || c.includes('clear')) return '☀️';
                        if (c.includes('cloud')) return '☁️';
                        if (c.includes('rain') || c.includes('shower')) return '🌧️';
                        if (c.includes('storm') || c.includes('thunder')) return '⛈️';
                        if (c.includes('snow')) return '❄️';
                        if (c.includes('wind')) return '🌬️';
                        if (c.includes('fog') || c.includes('mist') || c.includes('haze')) return '🌫️';
                        if (c.includes('hail')) return '🌨️';
                        if (c.includes('drizzle')) return '🌦️';
                        return '🌡️';
                      })()}
                    </span>
                    {props.condition}
                  </Text>
                </Stack>
              </Stack>
            </Stack>

            <Stack
              gap={12}
              direction="horizontal"
              wrap
              style={{
                flex: '1 1 420px',
                minWidth: 280,
                justifyContent: 'flex-start',
              }}
            >
              <div style={metricBoxStyle}>
                <Stack gap={4}>
                  <Text variant="caption" color={onSurfaceVariant}>
                    Humidity
                  </Text>
                  <Text variant="label" color={onSurface}>
                    {props.humidity}%
                  </Text>
                </Stack>
              </div>

              <div style={metricBoxStyle}>
                <Stack gap={4}>
                  <Text variant="caption" color={onSurfaceVariant}>
                    Wind speed
                  </Text>
                  <Text variant="label" color={onSurface}>
                    {props.windSpeed}
                  </Text>
                </Stack>
              </div>
            </Stack>
          </div>

          <Divider margin={0} color={outline} />

          <div
            style={{
              background: 'var(--ggui-color-primary-50, var(--ggui-color-container, #ede9fe))',
              borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
              border: `1px solid ${outline}`,
              padding: 'var(--ggui-spacing-4, 16px)',
            }}
          >
            <Stack direction="horizontal" gap={0} justify="between" align="stretch" wrap={false}>
              {forecastSlots.map((item, idx) => {
                const dayText = item.day ?? '—';
                const iconText = item.icon ?? ' ';
                const highText = item.high ?? undefined;
                const lowText = item.low ?? undefined;

                const highLine = highText ?? '—';
                const lowLine = lowText ?? '—';

                return (
                  <div
                    key={`${idx}-${dayText}`}
                    style={{
                      flex: 1,
                      minWidth: 0,
                      display: 'flex',
                      flexDirection: 'column',
                      alignItems: 'center',
                      textAlign: 'center',
                      paddingLeft: idx === 0 ? 'var(--ggui-spacing-0, 0px)' : 'var(--ggui-spacing-4, 16px)',
                      paddingRight:
                        idx === 4 ? 'var(--ggui-spacing-0, 0px)' : 'var(--ggui-spacing-4, 16px)',
                      borderLeft: idx === 0 ? undefined : `1px solid ${outline}`,
                    }}
                  >
                    <Text variant="caption" color={onSurfaceVariant}>
                      {dayText}
                    </Text>

                    <Text variant="bodyLarge" color={onSurface} style={{ lineHeight: 1.25 } as React.CSSProperties}>
                      {iconText}
                    </Text>

                    <Text variant="bodySmall" color={onSurfaceVariant}>
                      {highLine} / {lowLine}
                    </Text>
                  </div>
                );
              })}
            </Stack>
          </div>
        </Stack>
      </Card>
    </Container>
  );
}
